namespace YourApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateOnly LastInspected);

public interface IEquipmentService
{
    Task<List<EquipmentItem>> GetAllAsync();
}

public class EquipmentService : IEquipmentService
{
    public async Task<List<EquipmentItem>> GetAllAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Hydraulic Press #4", "Building A - Floor 2", new DateOnly(2026, 4, 10)),
            new(2, "CNC Lathe M200", "Building B - Shop 1", new DateOnly(2026, 3, 22)),
            new(3, "Forklift FL-09", "Warehouse C", new DateOnly(2026, 5, 01)),
            new(4, "Conveyor Belt Section 7", "Building A - Floor 1", new DateOnly(2025, 12, 15)),
            new(5, "Industrial Oven #2", "Building D - Lab", new DateOnly(2026, 1, 30)),
            new(6, "Welding Station W3", "Building B - Shop 2", new DateOnly(2026, 5, 18)),
            new(7, "Air Compressor AC-12", "Utility Room", new DateOnly(2026, 2, 28)),
        };
    }
}

@page "/inventory"
@using YourApp.Services
@attribute [StreamRendering]
@rendermode InteractiveServer
@inject IEquipmentService EquipmentService

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToString("yyyy-MM-dd")</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? items;

    protected override async Task OnInitializedAsync()
    {
        items = await EquipmentService.GetAllAsync();
    }
}

